            :key="a.id || idx"
            type="button"
            class="kb-web-action-btn"
            :class="{ 'kb-web-action-btn--secondary': Number(idx) > 0 }"
          >
            {{ a.label || 'Action' }}
          </button>
        </div>
        <p v-if="hiddenActionCount > 0" class="kb-preview-warning">
          Showing {{ visibleActions.length }} of {{ actions.length }} actions on {{ selectedPlatform }}.
        </p>
      </div>
    </div>
  </div>
</template>

